        log.LogInformation("Client IP: {ip}", req.HttpContext.Connection.RemoteIpAddress);
    }

    private static async Task<string> LogRequestBody(HttpRequest req, ILogger log)
    {
        log.LogInformation("=== REQUEST BODY ===");
        string requestBody = string.Empty;
        
        using (StreamReader reader = new StreamReader(req.Body, Encoding.UTF8, true, 1024, true))
        {
            requestBody = await reader.ReadToEndAsync();
            req.Body.Position = 0;
        }
        
        log.LogInformation("Request Body Length: {length}", requestBody.Length);
        log.LogInformation("Request Body Content: {body}", requestBody);
        
        try
        {
            var jsonObject = JsonConvert.DeserializeObject(requestBody);
