    private static async Task LogAuthenticationInfo(HttpRequest req, ILogger log)
    {
        log.LogInformation("=== AUTHENTICATION INFO ===");
        
        if (req.Headers.ContainsKey("Authorization"))
        {
            var authHeader = req.Headers["Authorization"].ToString();
            log.LogInformation("Authorization Header: {auth}", authHeader);
            
            if (authHeader.StartsWith("Bearer "))
            {
                var token = authHeader.Substring("Bearer ".Length);
                log.LogInformation("Bearer Token: {token}", token);
                log.LogInformation("Token Length: {length}", token.Length);
            }
        }
        
        if (req.Headers.ContainsKey("X-API-Key"))
        {
            log.LogInformation("API Key: {apiKey}", req.Headers["X-API-Key"].ToString());
        }
        
        if (req.Headers.ContainsKey("Cookie"))
        {
            log.LogInformation("Cookies: {cookies}", req.Headers["Cookie"].ToString());
        }
        
        if (req.HttpContext.User?.Identity?.IsAuthenticated == true)
        {
            log.LogInformation("User Authenticated: {name}", req.HttpContext.User.Identity.Name);
            log.LogInformation("User Claims:");
            foreach (var claim in req.HttpContext.User.Claims)
            {
                log.LogInformation("  Claim: {type} = {value}", claim.Type, claim.Value);
            }
        }
    }

