    private static async Task LogFullException(Exception ex, ILogger log)
    {
        log.LogError("=== EXCEPTION DETAILS ===");
        log.LogError("Exception Type: {type}", ex.GetType().FullName);
        log.LogError("Exception Message: {message}", ex.Message);
        log.LogError("Exception Source: {source}", ex.Source);
        log.LogError("Exception HResult: {hresult}", ex.HResult);
        log.LogError("Exception Stack Trace: {stackTrace}", ex.StackTrace);
        log.LogError("Exception Target Site: {targetSite}", ex.TargetSite);
        
        if (ex.Data.Count > 0)
        {
            log.LogError("Exception Data:");
            foreach (var key in ex.Data.Keys)
            {
                log.LogError("  {key} = {value}", key, ex.Data[key]);
            }
        }
        
        if (ex.InnerException != null)
        {
            log.LogError("=== INNER EXCEPTION ===");
            log.LogError("Inner Exception Type: {type}", ex.InnerException.GetType().FullName);
            log.LogError("Inner Exception Message: {message}", ex.InnerException.Message);
            log.LogError("Inner Exception Stack Trace: {stackTrace}", ex.InnerException.StackTrace);
            
            if (ex.InnerException.InnerException != null)
            {
                log.LogError("=== NESTED INNER EXCEPTION ===");
                log.LogError("Nested Exception Type: {type}", ex.InnerException.InnerException.GetType().FullName);
                log.LogError("Nested Exception Message: {message}", ex.InnerException.InnerException.Message);
                log.LogError("Nested Exception Stack Trace: {stackTrace}", ex.InnerException.InnerException.StackTrace);
            }
        }
        
        if (ex is SqlException sqlEx)
        {
            log.LogError("=== SQL EXCEPTION DETAILS ===");
            log.LogError("SQL Error Number: {number}", sqlEx.Number);
            log.LogError("SQL Error State: {state}", sqlEx.State);
            log.LogError("SQL Error Class: {class}", sqlEx.Class);
            log.LogError("SQL Server: {server}", sqlEx.Server);
            log.LogError("SQL Procedure: {procedure}", sqlEx.Procedure);
            log.LogError("SQL Line Number: {line}", sqlEx.LineNumber);
            
            foreach (SqlError error in sqlEx.Errors)
            {
                log.LogError("SQL Error Detail: Number={number}, Message={message}, State={state}, Class={class}",
                    error.Number, error.Message, error.State, error.Class);
            }
        }
        
        log.LogError("Exception ToString: {exception}", ex.ToString());
    }
